const anyCursed = (items: any[]): boolean => items.some((i) => i.cursed);

const applyPercent = (amount: number, percent: number): number =>
  Math.ceil((amount * percent) / 100);

const FIRST_INSURANCE_PERCENT = 110;
const CURSED_PERCENT = 150;
const FIXED_FEE = 5;

const rawBaseFor = (items: any[]): number =>
  isThreeAlikeBundle(items)
    ? THREE_ALIKE_BUNDLE_BASE
    : basePriceByItemType[items[0].type];

const quotePremium = (items: any[]): number => {
  const base = rawBaseFor(items);
  const afterCursed = anyCursed(items) ? applyPercent(base, CURSED_PERCENT) : base;
  const afterFirstInsurance = applyPercent(afterCursed, FIRST_INSURANCE_PERCENT);
  return afterFirstInsurance + FIXED_FEE;
};
